const items = $input.all().filter(i => i.json && i.json.id);
const emails = items.map((it, idx) => {
  const j = it.json;
  const from = (j.from && (j.from.value?.[0]?.address || j.from.text)) || j.From || j.from || 'unknown';
  const subject = j.subject || j.Subject || '(no subject)';
  const raw = (j.text || j.textHtml || j.html || j.snippet || '').toString();
  const body = raw.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1500);
  return { index: idx + 1, sender: from, subject, body };
});
let digest = emails.map(e => `#${e.index} | From: ${e.sender} | Subject: ${e.subject}\n${e.body}`).join('\n\n---\n\n');
if (digest.length > 30000) digest = digest.slice(0, 30000);
return [{ json: { email_count: emails.length, digest_text: digest } }];

