const o = $input.first().json.output || $input.first().json;
const urgent = (o.items || []).filter(i => i.category === 'Urgent' || Number(i.urgency) >= 4);
const lines = urgent.map(i => {
  const ai = (i.action_items && i.action_items.length) ? `\n   \u27a4 ${i.action_items.join('; ')}` : '';
  const dl = i.deadline ? ` (due ${i.deadline})` : '';
  return `\u2022 *${i.subject}* \u2014 ${i.sender}${dl}\n   ${i.summary}${ai}`;
});
const text = `\ud83d\udea8 *${urgent.length} urgent email${urgent.length === 1 ? '' : 's'} need your attention*\n\n` + lines.join('\n\n');
return [{ json: { urgent_text: text, urgent_count: urgent.length } }];

const o = $input.first().json.output || $input.first().json;
const items = o.items || [];
const cats = ['Urgent', 'Action needed', 'FYI', 'Newsletter'];
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: '\ud83d\udcec Daily Inbox Briefing', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*TL;DR:* ${o.tldr || ''}\n*${items.length}* emails \u00b7 *${o.urgent_count || 0}* urgent` } });
blocks.push({ type: 'divider' });
for (const c of cats) {
  const group = items.filter(i => i.category === c);
  if (!group.length) continue;
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*${c}* (${group.length})` } });
  for (const i of group) {
    const ai = (i.action_items && i.action_items.length) ? `\n   \u27a4 ${i.action_items.join('; ')}` : '';
    const dl = i.deadline ? ` _(due ${i.deadline})_` : '';
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: `\u2022 *${i.subject}* \u2014 ${i.sender}${dl}\n   ${i.summary}${ai}` } });
  }
  blocks.push({ type: 'divider' });
}
return [{ json: { blocks_json: JSON.stringify(blocks) } }];
